import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { chatsService } from '../services/chats.service';
import { asHttpError } from '../services/http';
import {
  connectChatSocket,
  joinThreadRoom,
  leaveThreadRoom,
  onChatSocketError,
  onMessageCreated,
  onOfferUpdated,
  onThreadCreated,
} from '../services/socket';
import { useAuthStore } from '../store/authStore';
import { useChatMetaStore } from '../store/chatMetaStore';
import { useNotificationStore } from '../store/notificationStore';
import type { ChatMessage, ThreadSummary } from '../types/domain';
import { parseOfferSystemMessage } from '../utils/chat';
import { formatDate } from '../utils/format';

type OfferAction = t('accept') | t('reject') | t('counter');

function upsertMessage(messages: ChatMessage[], nextMessage: ChatMessage): ChatMessage[] {
  const index = messages.findIndex((message) => message.id === nextMessage.id);
  if (index >= 0) {
    const cloned = [...messages];
    cloned[index] = nextMessage;
    return cloned;
  }

  return [...messages, nextMessage];
}

export function ChatPage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const currentUserId = useAuthStore((state) => state.user?.id ?? 0);
  const accessToken = useAuthStore((state) => state.accessToken);
  const setUnreadCount = useChatMetaStore((state) => state.setUnreadCount);
  const markThreadAsRead = useNotificationStore((state) => state.markThreadAsRead);

  const [threads, setThreads] = useState<ThreadSummary[]>([]);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [loadingThreads, setLoadingThreads] = useState(false);
  const [loadingMessages, setLoadingMessages] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [messageText, setMessageText] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [offerAmount, setOfferAmount] = useState('');
  const [offerQuantity, setOfferQuantity] = useState('1');
  const [offerMessage, setOfferMessage] = useState('');
  const [phoneMessage, setPhoneMessage] = useState('');
  const [offerIdToRespond, setOfferIdToRespond] = useState('');
  const [offerAction, setOfferAction] = useState<OfferAction>(t('accept'));
  const [counterAmount, setCounterAmount] = useState('');
  const [statusMessage, setStatusMessage] = useState<string | null>(null);

  const selectedThreadId = useMemo(() => {
    const raw = searchParams.get('thread');
    const id = Number(raw);
    return Number.isFinite(id) && id > 0 ? id : null;
  }, [searchParams]);

  const orderedMessages = useMemo(
    () => [...messages].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()),
    [messages],
  );
  const selectedThreadIdRef = useRef<number | null>(selectedThreadId);

  useEffect(() => {
    selectedThreadIdRef.current = selectedThreadId;
  }, [selectedThreadId]);

  const loadThreads = useCallback(async () => {
    setLoadingThreads(true);
    setError(null);
    try {
      const result = await chatsService.listThreads();
      setThreads(result.items);
      setUnreadCount(result.items.reduce((count, thread) => count + thread.unreadCount, 0));

      if (!selectedThreadId && result.items.length > 0) {
        setSearchParams({ thread: String(result.items[0].id) });
      }
    } catch (err) {
      setError(asHttpError(err).message);
    } finally {
      setLoadingThreads(false);
    }
  }, [selectedThreadId, setSearchParams, setUnreadCount]);

  const loadMessages = useCallback(async (threadId: number) => {
    setLoadingMessages(true);
    setError(null);
    try {
      const result = await chatsService.listMessages(threadId, 1, 100);
      setMessages(result.items);
    } catch (err) {
      setError(asHttpError(err).message);
    } finally {
      setLoadingMessages(false);
    }
  }, [t]);

  useEffect(() => {
    void loadThreads();
  }, [loadThreads]);

  useEffect(() => {
    if (!selectedThreadId) {
      setMessages([]);
      return;
    }

    void (async () => {
      await loadMessages(selectedThreadId);
      await loadThreads();
    })();
    markThreadAsRead(selectedThreadId);
  }, [selectedThreadId, loadMessages, loadThreads, markThreadAsRead]);

  useEffect(() => {
    if (!accessToken) {
      return;
    }

    connectChatSocket(accessToken);

    const unsubscribeThreadCreated = onThreadCreated(() => {
      void loadThreads();
    });

    const unsubscribeMessageCreated = onMessageCreated((payload) => {
      void loadThreads();

      if (selectedThreadIdRef.current && payload.threadId === selectedThreadIdRef.current) {
        setMessages((prev) => upsertMessage(prev, payload.message));
      }
    });

    const unsubscribeOfferUpdated = onOfferUpdated((payload) => {
      void loadThreads();
      if (selectedThreadIdRef.current && payload.threadId === selectedThreadIdRef.current) {
        void loadMessages(selectedThreadIdRef.current);
      }
    });

    const unsubscribeSocketError = onChatSocketError((payload) => {
      if (payload.code) {
        setStatusMessage(`Socket warning: ${payload.code}`);
      }
    });

    return () => {
      unsubscribeThreadCreated();
      unsubscribeMessageCreated();
      unsubscribeOfferUpdated();
      unsubscribeSocketError();
    };
  }, [accessToken, loadMessages, loadThreads]);

  useEffect(() => {
    if (!selectedThreadId) {
      return;
    }

    joinThreadRoom(selectedThreadId);
    return () => {
      leaveThreadRoom(selectedThreadId);
    };
  }, [selectedThreadId]);

  const sendTextMessage = async () => {
    if (!selectedThreadId || !messageText.trim()) return;
    setStatusMessage(null);
    try {
      await chatsService.sendMessage(selectedThreadId, { type: 'TEXT', content: messageText.trim() });
      setMessageText('');
      await loadMessages(selectedThreadId);
      await loadThreads();
    } catch (err) {
      setStatusMessage(asHttpError(err).message);
    }
  };

  const sendImageMessage = async () => {
    if (!selectedThreadId || !imageUrl.trim()) return;
    setStatusMessage(null);
    try {
      await chatsService.sendMessage(selectedThreadId, { type: 'IMAGE', imageUrl: imageUrl.trim() });
      setImageUrl('');
      await loadMessages(selectedThreadId);
      await loadThreads();
    } catch (err) {
      setStatusMessage(asHttpError(err).message);
    }
  };

  const sendOffer = async () => {
    if (!selectedThreadId) return;
    const amount = Number(offerAmount);
    const quantity = Number(offerQuantity);
    if (!Number.isFinite(amount) || amount <= 0 || !Number.isFinite(quantity) || quantity <= 0) return;

    setStatusMessage(null);
    try {
      const offer = await chatsService.createOffer(selectedThreadId, {
        amount,
        quantity,
        message: offerMessage || undefined,
      });
      setOfferIdToRespond(String(offer.id));
      setOfferAmount('');
      setOfferQuantity('1');
      setOfferMessage('');
      await loadMessages(selectedThreadId);
      await loadThreads();
      setStatusMessage(`Offer #${offer.id} created.`);
    } catch (err) {
      setStatusMessage(asHttpError(err).message);
    }
  };

  const requestPhone = async () => {
    if (!selectedThreadId) return;
    setStatusMessage(null);
    try {
      await chatsService.requestPhone(selectedThreadId, phoneMessage || undefined);
      setPhoneMessage('');
      await loadMessages(selectedThreadId);
      await loadThreads();
    } catch (err) {
      setStatusMessage(asHttpError(err).message);
    }
  };

  const respondToOffer = async () => {
    const offerId = Number(offerIdToRespond);
    if (!Number.isFinite(offerId) || offerId <= 0) return;

    setStatusMessage(null);
    try {
      await chatsService.respondOffer(offerId, {
        action: offerAction,
        counterAmount: offerAction === t('counter') ? Number(counterAmount) || undefined : undefined,
      });
      setCounterAmount('');
      if (selectedThreadId) {
        await loadMessages(selectedThreadId);
        await loadThreads();
      }
      setStatusMessage(`Offer #${offerId} updated.`);
    } catch (err) {
      setStatusMessage(asHttpError(err).message);
    }
  };

  return (
    <div className="stack">
      <h1 className="page-title">{t('title')}</h1>
      <p className="page-subtitle">{t('subtitle')}</p>

      {error ? <p className="error-text">{error}</p> : null}
      {statusMessage ? <p className="muted-text">{statusMessage}</p> : null}

      <section className="split">
        <aside className="split__aside card">
          <div className="card__header">
            <h2>{t('threads')}</h2>
            <button type="button" className="button button--ghost" onClick={() => void loadThreads()} disabled={loadingThreads}>{t('refresh')}</button>
          </div>

          <div className="list">
            {threads.map((thread) => (
              <button
                type="button"
                key={thread.id}
                className={selectedThreadId === thread.id ? 'thread-item thread-item--active' : 'thread-item'}
                onClick={() => setSearchParams({ thread: String(thread.id) })}
              >
                <div className="row__title">
                  {thread.listing.title}
                  {thread.unreadCount > 0 ? <span className="thread-counter">{thread.unreadCount}</span> : null}
                </div>
                <div className="row__meta">
                  Last: {thread.lastMessage?.content ?? t('noMessageYet')} - {formatDate(thread.lastMessageAt)}
                </div>
              </button>
            ))}
            {!loadingThreads && threads.length === 0 ? <p className="muted-text">{t('noThreads')}</p> : null}
          </div>
        </aside>

        <section className="split__main card">
          <div className="card__header">
            <h2>{t('messages')}</h2>
            <span className="muted-text">{selectedThreadId ? `Thread #${selectedThreadId}` : t('noThreadSelected')}</span>
          </div>

          <div className="messages">
            {loadingMessages ? <p className="muted-text">{t('loadingMessages')}</p> : null}
            {orderedMessages.map((message) => {
              const isOwn = message.senderId === currentUserId;
              const offerMessage = message.type === 'OFFER' ? parseOfferSystemMessage(message.content) : null;

              return (
                <article key={message.id} className={isOwn ? 'message message--own' : 'message'}>
                  <div className="row__meta">
                    #{message.id} - {message.type} - {formatDate(message.createdAt)}
                  </div>
                  {offerMessage ? (
                    <div>
                      Offer #{offerMessage.offerId}: amount {offerMessage.amount} x {offerMessage.quantity} ({offerMessage.status})
                    </div>
                  ) : (
                    <div>{message.content || message.imageUrl || '-'}</div>
                  )}
                </article>
              );
            })}
            {!loadingMessages && orderedMessages.length === 0 ? <p className="muted-text">{t('noMessagesYet')}</p> : null}
          </div>

          <div className="grid grid--2" style={{ marginTop: '0.8rem' }}>
            <div className="card">
              <h3>{t('sendMessage')}</h3>
              <div className="stack">
                <label className="field">
                  <span className="label">{t('textMessage')}</span>
                  <input className="input" value={messageText} onChange={(event) => setMessageText(event.target.value)} />
                </label>
                <div className="button-row">
                  <button type="button" className="button button--primary" onClick={sendTextMessage} disabled={!selectedThreadId}>{t('sendText')}</button>
                </div>

                <label className="field">
                  <span className="label">{t('imageUrl')}</span>
                  <input className="input" value={imageUrl} onChange={(event) => setImageUrl(event.target.value)} />
                </label>
                <div className="button-row">
                  <button type="button" className="button button--secondary" onClick={sendImageMessage} disabled={!selectedThreadId}>{t('sendImage')}</button>
                </div>
              </div>
            </div>

            <div className="card">
              <h3>{t('negotiationTools')}</h3>
              <div className="stack">
                <label className="field">
                  <span className="label">{t('offerAmount')}</span>
                  <input
                    className="input"
                    type="number"
                    min={1}
                    value={offerAmount}
                    onChange={(event) => setOfferAmount(event.target.value)}
                  />
                </label>
                <label className="field">
                  <span className="label">{t('offerQuantity')}</span>
                  <input
                    className="input"
                    type="number"
                    min={1}
                    value={offerQuantity}
                    onChange={(event) => setOfferQuantity(event.target.value)}
                  />
                </label>
                <label className="field">
                  <span className="label">{t('offerMessage')}</span>
                  <input
                    className="input"
                    value={offerMessage}
                    onChange={(event) => setOfferMessage(event.target.value)}
                  />
                </label>
                <div className="button-row">
                  <button type="button" className="button button--warning" onClick={sendOffer} disabled={!selectedThreadId}>{t('sendOffer')}</button>
                </div>

                <label className="field">
                  <span className="label">{t('phoneRequestNote')}</span>
                  <input
                    className="input"
                    value={phoneMessage}
                    onChange={(event) => setPhoneMessage(event.target.value)}
                  />
                </label>
                <div className="button-row">
                  <button type="button" className="button button--secondary" onClick={requestPhone} disabled={!selectedThreadId}>{t('requestPhone')}</button>
                </div>

                <hr />

                <label className="field">
                  <span className="label">{t('offerId')}</span>
                  <input
                    className="input"
                    type="number"
                    min={1}
                    value={offerIdToRespond}
                    onChange={(event) => setOfferIdToRespond(event.target.value)}
                  />
                </label>
                <label className="field">
                  <span className="label">{t('action')}</span>
                  <select
                    className="select"
                    value={offerAction}
                    onChange={(event) => setOfferAction(event.target.value as OfferAction)}
                  >
                    <option value=t('accept')>{t(t('accept'))}</option>
                    <option value=t('reject')>{t(t('reject'))}</option>
                    <option value=t('counter')>{t(t('counter'))}</option>
                  </select>
                </label>
                {offerAction === t('counter') ? (
                  <label className="field">
                    <span className="label">{t('counterAmount')}</span>
                    <input
                      className="input"
                      type="number"
                      min={1}
                      value={counterAmount}
                      onChange={(event) => setCounterAmount(event.target.value)}
                    />
                  </label>
                ) : null}
                <div className="button-row">
                  <button type="button" className="button button--danger" onClick={respondToOffer}>{t('respondOffer')}</button>
                </div>
              </div>
            </div>
          </div>
        </section>
      </section>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { authService } from '../services/auth.service';
import { preferencesService } from '../services/preferences.service';
import { verificationService, type IdentityDocumentType } from '../services/verification.service';
import { asHttpError } from '../services/http';
import { useAuthStore } from '../store/authStore';
import type {
  FavoriteSummary,
  MyIdentityVerificationResult,
  NotificationFrequency,
  SavedSearch,
} from '../types/domain';
import { formatDate, formatMoney } from '../utils/format';

export function PreferencesPage() {
  const { t } = useTranslation('preferences');
  const user = useAuthStore((state) => state.user);
  const refreshUser = useAuthStore((state) => state.refreshUser);
  const [favorites, setFavorites] = useState<FavoriteSummary[]>([]);
  const [savedSearches, setSavedSearches] = useState<SavedSearch[]>([]);
  const [identityVerification, setIdentityVerification] = useState<MyIdentityVerificationResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const [favoriteListingId, setFavoriteListingId] = useState('');
  const [searchName, setSearchName] = useState('');
  const [searchFiltersText, setSearchFiltersText] = useState('{"q":"car","countryId":1}');
  const [searchFrequency, setSearchFrequency] = useState<NotificationFrequency>(t('daily'));
  const [phone, setPhone] = useState('');
  const [otpCode, setOtpCode] = useState('');
  const [otpRequested, setOtpRequested] = useState(false);
  const [identityDocumentType, setIdentityDocumentType] = useState<IdentityDocumentType>(t('nationalId'));
  const [identityDocumentNumberMasked, setIdentityDocumentNumberMasked] = useState('');
  const [identityDocumentFrontUrl, setIdentityDocumentFrontUrl] = useState('');
  const [identityDocumentBackUrl, setIdentityDocumentBackUrl] = useState('');
  const [identitySelfieUrl, setIdentitySelfieUrl] = useState('');
  const [identityNote, setIdentityNote] = useState('');

  useEffect(() => {
    setPhone(user?.phone ?? '');
  }, [user?.phone]);

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [favoritesResult, savedResult, identityResult] = await Promise.all([
        preferencesService.listFavorites(),
        preferencesService.listSavedSearches(),
        verificationService.getMyIdentityVerification(),
      ]);
      setFavorites(favoritesResult.items);
      setSavedSearches(savedResult.items);
      setIdentityVerification(identityResult);
    } catch (err) {
      setError(asHttpError(err).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    void loadData();
  }, []);

  const handleAddFavorite = async () => {
    const listingId = Number(favoriteListingId);
    if (!Number.isFinite(listingId) || listingId <= 0) return;

    setMessage(null);
    try {
      await preferencesService.addFavorite(listingId);
      setFavoriteListingId('');
      setMessage('Favorite added.');
      await loadData();
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  const handleRemoveFavorite = async (listingId: number) => {
    setMessage(null);
    try {
      await preferencesService.removeFavorite(listingId);
      setMessage('Favorite removed.');
      await loadData();
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  const handleCreateSavedSearch = async () => {
    setMessage(null);
    try {
      const parsedFilters = JSON.parse(searchFiltersText) as Record<string, unknown>;
      await preferencesService.createSavedSearch({
        name: searchName,
        filters: parsedFilters,
        notificationFrequency: searchFrequency,
      });
      setSearchName('');
      setMessage('Saved search created.');
      await loadData();
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  const handleDeleteSavedSearch = async (id: number) => {
    setMessage(null);
    try {
      await preferencesService.deleteSavedSearch(id);
      setMessage('Saved search deleted.');
      await loadData();
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  const handleRequestPhoneOtp = async () => {
    if (!phone.trim()) return;

    setMessage(null);
    try {
      const result = await authService.requestPhoneVerification(phone.trim());
      setOtpRequested(true);
      setMessage(`Verification code sent via ${result.channel}. Expires in ${result.expiresInSeconds} seconds.`);
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  const handleVerifyPhoneOtp = async () => {
    if (!phone.trim() || !otpCode.trim()) return;

    setMessage(null);
    try {
      const result = await authService.verifyPhoneOtp({
        phone: phone.trim(),
        code: otpCode.trim(),
      });
      setOtpCode('');
      setOtpRequested(false);
      setMessage(`Phone ${result.phone} verified successfully.`);
      await refreshUser();
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  const handleSubmitIdentityVerification = async () => {
    if (!identityDocumentFrontUrl.trim()) return;

    setMessage(null);
    try {
      await verificationService.submitIdentityVerification({
        documentType: identityDocumentType,
        documentNumberMasked: identityDocumentNumberMasked.trim() || undefined,
        documentFrontUrl: identityDocumentFrontUrl.trim(),
        documentBackUrl: identityDocumentBackUrl.trim() || undefined,
        selfieUrl: identitySelfieUrl.trim() || undefined,
        note: identityNote.trim() || undefined,
      });
      setMessage('Identity verification request submitted successfully.');
      setIdentityNote('');
      await refreshUser();
      await loadData();
    } catch (err) {
      setMessage(asHttpError(err).message);
    }
  };

  return (
    <div className="stack">
      <h1 className="page-title">{t('title')}</h1>
      <p className="page-subtitle">{t('subtitle')}</p>

      {error ? <p className="error-text">{error}</p> : null}
      {message ? <p className="muted-text">{message}</p> : null}

      <section className="card">
        <h2>{t('phoneVerification')}</h2>
        <div className="stack">
          <label className="field">
            <span className="label">{t('phoneNumber')}</span>
            <input
              className="input"
              placeholder="+9639XXXXXXXX"
              value={phone}
              onChange={(event) => setPhone(event.target.value)}
            />
          </label>

          <div className="button-row">
            <button type="button" className="button button--primary" onClick={handleRequestPhoneOtp}>{t('requestOtp')}</button>
          </div>

          {otpRequested ? (
            <>
              <label className="field">
                <span className="label">{t('otpCode')}</span>
                <input
                  className="input"
                  placeholder="123456"
                  value={otpCode}
                  onChange={(event) => setOtpCode(event.target.value)}
                />
              </label>
              <div className="button-row">
                <button type="button" className="button button--secondary" onClick={handleVerifyPhoneOtp}>{t('verifyPhone')}</button>
              </div>
            </>
          ) : null}

          <p className="muted-text">
            Current verification status: {user?.phoneVerified ? t('verified') : t('notVerified')}
          </p>
        </div>
      </section>

      <section className="card">
        <h2>{t('identityVerification')}</h2>
        <div className="stack">
          <p className="muted-text">
            Current status: {user?.identityVerificationStatus ?? t('none')}
            {user?.identityVerifiedAt ? ` (verified at ${formatDate(user.identityVerifiedAt)})` : ''}
          </p>

          {identityVerification?.currentRequest ? (
            <p className="muted-text">
              Latest request: {identityVerification.currentRequest.documentType} - submitted{' '}
              {formatDate(identityVerification.currentRequest.submittedAt)}
              {identityVerification.currentRequest.reviewedAt
                ? ` - reviewed ${formatDate(identityVerification.currentRequest.reviewedAt)}`
                : ''}
            </p>
          ) : (
            <p className="muted-text">{t('noIdentityRequest')}</p>
          )}

          <label className="field">
            <span className="label">{t('documentType')}</span>
            <select
              className="select"
              value={identityDocumentType}
              onChange={(event) => setIdentityDocumentType(event.target.value as IdentityDocumentType)}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            >
              <option value=t('nationalId')>{t('nationalId')}</option>
              <option value=t('passport')>{t('passport')}</option>
              <option value=t('driverLicense')>{t('driverLicense')}</option>
              <option value=t('other')>{t('other')}</option>
            </select>
          </label>

          <label className="field">
            <span className="label">{t('documentNumber')}</span>
            <input
              className="input"
              placeholder="****1234"
              value={identityDocumentNumberMasked}
              onChange={(event) => setIdentityDocumentNumberMasked(event.target.value)}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            />
          </label>

          <label className="field">
            <span className="label">{t('documentFront')}</span>
            <input
              className="input"
              placeholder="https://..."
              value={identityDocumentFrontUrl}
              onChange={(event) => setIdentityDocumentFrontUrl(event.target.value)}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            />
          </label>

          <label className="field">
            <span className="label">{t('documentBack')}</span>
            <input
              className="input"
              placeholder="https://..."
              value={identityDocumentBackUrl}
              onChange={(event) => setIdentityDocumentBackUrl(event.target.value)}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            />
          </label>

          <label className="field">
            <span className="label">{t('selfieUrl')}</span>
            <input
              className="input"
              placeholder="https://..."
              value={identitySelfieUrl}
              onChange={(event) => setIdentitySelfieUrl(event.target.value)}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            />
          </label>

          <label className="field">
            <span className="label">{t('note')}</span>
            <textarea
              className="textarea"
              value={identityNote}
              onChange={(event) => setIdentityNote(event.target.value)}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            />
          </label>

          <div className="button-row">
            <button
              type="button"
              className="button button--primary"
              onClick={handleSubmitIdentityVerification}
              disabled={identityVerification ? !identityVerification.canSubmit : false}
            >{t('submitIdentity')}</button>
          </div>
        </div>
      </section>

      <section className="grid grid--2">
        <div className="card">
          <h2>{t('favorites')}</h2>
          <div className="inline" style={{ marginBottom: '0.65rem' }}>
            <input
              className="input"
              type="number"
              min={1}
              placeholder={t('listingId')}
              value={favoriteListingId}
              onChange={(event) => setFavoriteListingId(event.target.value)}
            />
            <button type="button" className="button button--primary" onClick={handleAddFavorite}>{t('add')}</button>
            <button type="button" className="button button--ghost" onClick={loadData} disabled={loading}>{t('refresh')}</button>
          </div>

          <div className="list">
            {favorites.map((favorite) => (
              <div key={favorite.favoriteId} className="row">
                <div className="row__title">
                  <Link to={`/listings/${favorite.listing.id}`}>{favorite.listing.title}</Link>
                </div>
                <div className="row__meta">
                  {formatMoney(favorite.listing.priceAmount, favorite.listing.currency)} • {favorite.listing.countryName} /{' '}
                  {favorite.listing.cityName} • Added {formatDate(favorite.createdAt)}
                </div>
                <div className="button-row">
                  <button
                    type="button"
                    className="button button--danger"
                    onClick={() => handleRemoveFavorite(favorite.listing.id)}
                  >{t('remove')}</button>
                </div>
              </div>
            ))}
            {!loading && favorites.length === 0 ? <p className="muted-text">{t('noFavorites')}</p> : null}
          </div>
        </div>

        <div className="card">
          <h2>{t('savedSearches')}</h2>
          <div className="stack" style={{ marginBottom: '0.75rem' }}>
            <label className="field">
              <span className="label">{t('name')}</span>
              <input className="input" value={searchName} onChange={(event) => setSearchName(event.target.value)} />
            </label>
            <label className="field">
              <span className="label">{t('filtersJson')}</span>
              <textarea
                className="textarea"
                value={searchFiltersText}
                onChange={(event) => setSearchFiltersText(event.target.value)}
              />
            </label>
            <label className="field">
              <span className="label">{t('frequency')}</span>
              <select
                className="select"
                value={searchFrequency}
                onChange={(event) => setSearchFrequency(event.target.value as NotificationFrequency)}
              >
                <option value=t('instant')>{t(t('instant'))}</option>
                <option value=t('daily')>{t(t('daily'))}</option>
                <option value=t('weekly')>{t(t('weekly'))}</option>
              </select>
            </label>
            <div className="button-row">
              <button type="button" className="button button--primary" onClick={handleCreateSavedSearch}>{t('saveSearch')}</button>
            </div>
          </div>

          <div className="list">
            {savedSearches.map((savedSearch) => (
              <div key={savedSearch.id} className="row">
                <div className="row__title">
                  {savedSearch.name} ({savedSearch.notificationFrequency})
                </div>
                <pre className="row__meta" style={{ whiteSpace: 'pre-wrap' }}>
                  {JSON.stringify(savedSearch.filters, null, 2)}
                </pre>
                <div className="row__meta">Created {formatDate(savedSearch.createdAt)}</div>
                <div className="button-row">
                  <button
                    type="button"
                    className="button button--danger"
                    onClick={() => handleDeleteSavedSearch(savedSearch.id)}
                  >{t('delete')}</button>
                </div>
              </div>
            ))}
            {!loading && savedSearches.length === 0 ? <p className="muted-text">{t('noSavedSearches')}</p> : null}
          </div>
        </div>
      </section>
    </div>
  );
}
